441→// 查询汇报人和抄送人
442→async function getReportsSuperiorAPI(): Promise<Record<string, string[]>> {
443→    const params = {
444→        sys_aggregate: true,
445→        decrypt_config: {},
446→    }
447→    params.decrypt_config = {
448→        obj: '$this',
449→        decrypt_columns: ['cc_user.*', 'report_user.*'],
450→    }
451→
452→    const p = handlerParams(params)
453→
454→    try {
455→        const res = await axiosPostWithInt(ajaxUrl.UserAPI + 'daily-report/get-to-report-users', p)
456→        const allReportUsers = {}
457→        Object.keys(res.data)
458→            .map(item => res.data[item].data)
459→            .forEach(item => {
460→                Object.keys(item).forEach(val => {
461→                    if (allReportUsers[val]) {
462→                        allReportUsers[val].push(...item[val])
463→                    } else {
464→                        allReportUsers[val] = item[val]
465→                    }
466→                })
467→            })
468→        return allReportUsers
469→    } catch (e) {
470→        Message.error(e?.error_msg)
471→        console.error(e?.error_msg)
472→    }
473→}
